\begin{definition}
[Underlying sheaf of a line bundle on the product]
  \label{def:OnProduct_carrier}
  \lean{AlgebraicGeometry.Scheme.LineBundle.OnProduct.carrier}
  \uses{def:line_bundle_on_product, def:IsLocallyTrivial}
  The \emph{underlying sheaf of modules} of a line bundle
  \(\mathcal{L} \in \mathrm{OnProduct}\,\pi_C\,\pi_T\)
  (\cref{def:line_bundle_on_product}) is its first component, the
  \(\mathcal{O}_{C \times_k T}\)-module \(\mathcal{L}.\mathrm{carrier}\) obtained
  by forgetting the local-triviality witness. Since
  \(\mathrm{OnProduct}\,\pi_C\,\pi_T\) is the subtype
  \(\{\,\mathcal{M} : (C \times_k T).\mathrm{Modules} \mid
  \mathtt{IsLocallyTrivial}\,\mathcal{M}\,\}\) of
  \cref{def:line_bundle_on_product}, the carrier is the underlying
  \((C \times_k T).\mathrm{Modules}\) value, recovering the all-modules
  carrier of \cref{def:line_bundle_on_product} by projecting away the second
  (invertibility) component.
\end{definition}

\begin{lemma}
[A line bundle on the product is locally trivial]
  \label{lem:OnProduct_isLocallyTrivial}
  \lean{AlgebraicGeometry.Scheme.LineBundle.OnProduct.isLocallyTrivial}
  \uses{def:line_bundle_on_product, def:OnProduct_carrier, def:IsLocallyTrivial}
  For any line bundle \(\mathcal{L} \in \mathrm{OnProduct}\,\pi_C\,\pi_T\)
  (\cref{def:line_bundle_on_product}), the underlying sheaf of modules
  \(\mathcal{L}.\mathrm{carrier}\) (\cref{def:OnProduct_carrier}) is locally
  trivial of rank one in the sense of \cref{def:IsLocallyTrivial}. This is the
  second component of the subtype, the invertibility witness packaged with the
  carrier.
\end{lemma}
\begin{proof}
  \uses{def:IsLocallyTrivial}
  Proved directly in Lean: the local-triviality witness is the defining second
  component of the subtype \(\mathrm{OnProduct}\,\pi_C\,\pi_T\).
\end{proof}

